   206→            let pattern = format!("%{term}%");
   207→            q = q.bind(pattern.clone()).bind(pattern.clone()).bind(pattern);
   208→        }
   209→        q = q.bind(limit as i64).bind(offset as i64);
   210→
   211→        let rows = q.fetch_all(&self.pool).await?;
   212→        rows.into_iter().map(Contact::try_from).collect()
   213→    }
