   236→    async fn upsert(&self, contact: Contact) -> Result<()> {
   237→        use secrecy::ExposeSecret;
   238→        let metadata = serde_json::to_string(&contact.metadata)?;
   239→        sqlx::query(
   240→            r#"INSERT INTO crm_contacts
   241→               (id, name, source, external_id, email, phone, stage, metadata, created_at, updated_at)
   242→               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
   243→               ON CONFLICT(id) DO UPDATE SET
   244→                 name        = excluded.name,
   245→                 source      = excluded.source,
   246→                 external_id = excluded.external_id,
   247→                 email       = excluded.email,
   248→                 phone       = excluded.phone,
   249→                 stage       = excluded.stage,
   250→                 metadata    = excluded.metadata,
   251→                 updated_at  = excluded.updated_at"#,
   252→        )
   253→        .bind(&contact.id)
   254→        .bind(&contact.name)
   255→        .bind(&contact.source)
   256→        .bind(&contact.external_id)
   257→        .bind(contact.email.as_ref().map(|s| s.expose_secret().clone()))
   258→        .bind(contact.phone.as_ref().map(|s| s.expose_secret().clone()))
   259→        .bind(contact.stage.as_str())
   260→        .bind(&metadata)
   261→        .bind(contact.created_at as i64)
   262→        .bind(contact.updated_at as i64)
   263→        .execute(&self.pool)
   264→        .await?;
   265→        Ok(())
   266→    }
