               (id, contact_id, title, description, status, phase, practice_area, created_at, updated_at)
               VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
               ON CONFLICT(id) DO UPDATE SET
                 contact_id    = excluded.contact_id,
