        .bind(&matter.description)
        .bind(matter.status.as_str())
        .bind(matter.phase.as_str())
        .bind(matter.practice_area.as_str())
        .bind(matter.created_at as i64)
        .bind(matter.updated_at as i64)
        .execute(&self.pool)
