    let resource_limits = || {
        Struct(HashMap::from([
            ("memory_limit", Leaf),
            ("cpu_quota", Leaf),
            ("pids_max", Leaf),
        ]))
    };

    let wasm_tool_limit_override = || Struct(HashMap::from([("fuel", Leaf), ("memory", Leaf)]));

    let wasm_tool_limits = || {
        Struct(HashMap::from([
            ("default_memory", Leaf),
            ("default_fuel", Leaf),
            ("tool_overrides", Map(Box::new(wasm_tool_limit_override()))),
