        let result = validate_toml_str(toml);

        let conflict = result
            .diagnostics
            .iter()
            .find(|d| {
                d.category == "deprecated-field"
                    && d.severity == Severity::Error
                    && d.path == "memory.embedding_provider"
            })
            .unwrap_or_else(|| {
                panic!("expected targeted conflict error: {:?}", result.diagnostics)
            });
        assert!(
