        assert_eq!(preset.identity.name.as_deref(), Some("Code Bot"));
        assert_eq!(preset.model.as_deref(), Some("haiku"));
        assert_eq!(preset.timeout_secs, Some(30));
        assert_eq!(preset.tools.deny, vec!["exec".to_string()]);
    }
