fn spawn_post_listener_warmups(
    browser_service: Arc<dyn crate::services::BrowserService>,
    browser_tool: Option<Arc<dyn moltis_agents::tool_registry::AgentTool>>,
) {
    if !env_flag_enabled("MOLTIS_BROWSER_WARMUP") {
